pageContent:
.dashboard-container {
  padding: 20px;
  max-width: 1200px;
  margin: 0 auto;
}
h1 {
  text-align: center;
  color: #fff;
  margin-bottom: 30px;
}
.cards {
  display: flex;
  gap: 20px;
  margin-bottom: 30px;
}
.card {
  flex: 1;
  background: rgba(255,255,255,0.1);
  backdrop-filter: blur(5px);
  border-radius: 12px;
  padding: 20px;
  text-align: center;
  color: #fff;
}
.card h2 {
  margin-top: 0;
  font-size: 1.2rem;
  opacity: 0.8;
}
.card .value {
  font-size: 2rem;
  font-weight: bold;
  margin: 10px 0;
}
.placeholder {
  background: rgba(255,255,255,0.1);
  backdrop-filter: blur(5px);
  border-radius: 12px;
  padding: 30px;
  text-align: center;
  color: #fff;
}
.chart-placeholder {
  width: 100%;
  height: 200px;
  background: rgba(0,0,0,0.2);
  margin-top: 20px;
  border-radius: 8px;
}
.stat-card {
  background: rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  border: 1px solid rgba(212, 175, 55, 0.2);
  transition: transform 0.3s;
}

.stat-card:hover {
  transform: translateY(-5px);
  border-color: #d4af37;
}

.icon-box {
  width: 50px;
  height: 50px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
}
